const staticData = $getWorkflowStaticData('global');
const lastProcessed = staticData.lastSalaryDate || '';

// fullResponse: body enthält den kompletten Array
const arr = $input.first().json.body;

const salary = arr.find(t => {
  const name = (t.applicant_name || '').toLowerCase();
  const amt = parseFloat(t.amount || 0);
  return name.includes('mandala') && amt > 1000 && t.date !== lastProcessed;
});

if (!salary) return [{ json: { newSalary: false } }];

staticData.lastSalaryDate = salary.date;
return [{ json: { newSalary: true, salaryAmount: parseFloat(salary.amount), salaryDate: salary.date } }];

const salaryData = $('Neues Gehalt prüfen').first().json;
const salaryDate = salaryData.salaryDate;
const salary = salaryData.salaryAmount;
const salaryDay = new Date(salaryDate).getDate();

const balArr = $input.first().json.body;
const girokonto = balArr.find(a => (a.iban || '').endsWith('7000')) || balArr[0];
const currentBalance = parseFloat(girokonto.balance || 0);

const FIXKOSTEN = [
  { name: 'Miete (28.)',           amount: 470.00, nurVorDem28: true },
  { name: 'Allianz Lebensvers.',   amount: 130.00 },
  { name: 'Iris Moenig (Fahrrad)', amount: 140.00 },
  { name: 'Canada Life',           amount: 55.94  },
  { name: 'Telefonica',            amount: 43.23  },
  { name: 'Vattenfall (Strom)',    amount: 33.00  },
  { name: 'Martin Paun (Handy)',   amount: 30.00  },
  { name: 'Debeka KV',             amount: 28.29  },
  { name: 'ARAG',                  amount: 18.30  },
  { name: 'Claude Pro',            amount: 19.00  },
  { name: 'Barmenia',              amount: 4.61   },
];

const mieteSchonBezahlt = salaryDay >= 28;
const zuReservieren = FIXKOSTEN.filter(f => !(f.nurVorDem28 && mieteSchonBezahlt));
const reserve = zuReservieren.reduce((s, f) => s + f.amount, 0);
const transferAmount = currentBalance - reserve;

const fmt = n => n.toLocaleString('de-DE', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

let msg = '\u{1F4B0} *Gehaltseingang \u2013 ' + fmt(salary) + ' \u20AC*\n';
msg += '\u{1F3E6} *Kontostand: ' + fmt(currentBalance) + ' \u20AC*\n';
msg += '\u{1F4C5} ' + new Date(salaryDate).toLocaleDateString('de-DE') + '\n\n';

if (mieteSchonBezahlt) {
  msg += '\u2705 *Miete bereits abgebucht*\n\n';
}

msg += '\u{1F4CB} *Reserviert f\u00FCr Folgemonat:*\n';
zuReservieren.forEach(f => { msg += '  \u2022 ' + f.name + ': ' + fmt(f.amount) + ' \u20AC\n'; });
msg += '  \u2211 *' + fmt(reserve) + ' \u20AC*\n\n';
msg += '\u{1F4B3} *\u2192 ' + fmt(transferAmount) + ' \u20AC auf C24 \u00FCberweisen*';

return [{ json: { message: msg, transferAmount, currentBalance, salary, reserve } }];

